from fastapi import FastAPI, Query
from fastapi.exceptions import RequestValidationError
from fastapi.responses import JSONResponse
from pydantic import BaseModel, Field, field_validator
from typing import Annotated

app = FastAPI()

class CreateUserRequest(BaseModel):
    username: Annotated[str, Field(min_length=3, max_length=30, pattern=r'^[a-z0-9_]+$')]
    email: Annotated[str, Field(max_length=255)]

    @field_validator('username', mode='before')
    @classmethod
    def normalize(cls, v: str) -> str:
        return v.strip().lower()

@app.exception_handler(RequestValidationError)
async def validation_error_handler(request, exc: RequestValidationError):
    return JSONResponse(status_code=400, content={"errors": exc.errors()})

@app.post("/users")
async def create_user(body: CreateUserRequest, q: Annotated[str | None, Query(max_length=50)] = None):
    return {"username": body.username}

from fastapi import Depends, HTTPException, status
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from jose import JWTError, jwt

bearer = HTTPBearer()
SECRET, ALGORITHM = "secret", "HS256"

def get_current_user(creds: HTTPAuthorizationCredentials = Depends(bearer)):
    try:
        payload = jwt.decode(creds.credentials, SECRET, algorithms=[ALGORITHM])
        return payload["sub"]
    except JWTError:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Invalid token")

@app.get("/me")
def me(user_id: str = Depends(get_current_user)):
    return {"user": user_id}

from fastapi import FastAPI, Request, HTTPException
from fastapi.exceptions import RequestValidationError
from fastapi.responses import JSONResponse
from starlette.exceptions import HTTPException as StarletteHTTPException

app = FastAPI()

def error_envelope(status: int, code: str, message: str) -> dict:
    return {"status": status, "error_code": code, "message": message}

@app.exception_handler(StarletteHTTPException)
async def http_handler(request: Request, exc: StarletteHTTPException):
    return JSONResponse(status_code=exc.status_code,
        content=error_envelope(exc.status_code, "HTTP_ERROR", exc.detail))

@app.exception_handler(RequestValidationError)
async def validation_handler(request: Request, exc: RequestValidationError):
    return JSONResponse(status_code=422,
        content=error_envelope(422, "VALIDATION_ERROR", str(exc.errors())))

@app.exception_handler(Exception)
async def unhandled_handler(request: Request, exc: Exception):
    return JSONResponse(status_code=500,
        content=error_envelope(500, "INTERNAL_ERROR", "Unexpected error"))

from functools import lru_cache
from pydantic import SecretStr
from pydantic_settings import BaseSettings, SettingsConfigDict

class Settings(BaseSettings):
    model_config = SettingsConfigDict(
        env_file=".env", secrets_dir="/run/secrets", env_file_encoding="utf-8"
    )
    database_url: str
    api_key: SecretStr
    debug: bool = False

